import { NextResponse } from "next/server";
import { auth } from "@/auth";
import PDFDocument from 'pdfkit/js/pdfkit.standalone.js'; 
import { query } from "@/lib/db";

export const dynamic = 'force-dynamic';

const LOGO_BASE64 = ""; // Replace with your complete string

export async function POST(request) {
    try {
        const session = await auth();
        if (!session?.user) return NextResponse.json({ success: false, message: "Unauthorized" }, { status: 403 });

        const {
            dateFrom,
            dateTo,
            showWorkType,
            showNatureOfWork,
            showTown,
            departments,
            workTypes,
            naturesOfWork,
            towns 
        } = await request.json();

        // --- isolated async runtime resolution for your font asset ---
        let fontBuffer = null;
        try {
            const fsPromises = (await import('fs/promises')).default;
            const path = (await import('path')).default;
            const fontPath = path.join(process.cwd(), 'public', 'fonts', 'arial.ttf');
            fontBuffer = await fsPromises.readFile(fontPath);
        } catch (fontReadError) {
            console.warn("Custom font missing, falling back to Helvetica:", fontReadError.message);
        }

        // 1. Build SQL WHERE Clause
        let whereClauses = ["1=1"];
        if (departments?.length > 0) {
            whereClauses.push(`wr.complaint_type_id IN (${departments.map(id => parseInt(id)).join(',')})`);
        }
        if (showWorkType && workTypes?.length > 0) {
            whereClauses.push(`wr.complaint_subtype_id IN (${workTypes.map(id => parseInt(id)).join(',')})`);
        }
        if (showNatureOfWork && naturesOfWork?.length > 0) {
            const natureList = naturesOfWork.map(n => n === 'null' ? 'NULL' : `'${n}'`).join(',');
            whereClauses.push(`wr.nature_of_work IN (${natureList})`);
        }
        if (showTown && towns?.length > 0) {
            whereClauses.push(`wr.town_id IN (${towns.map(id => parseInt(id)).join(',')})`);
        }

        if (dateFrom) whereClauses.push(`wr.request_date >= '${dateFrom}'`);
        if (dateTo) whereClauses.push(`wr.request_date <= '${dateTo}'`);

        const whereString = `WHERE ${whereClauses.join(' AND ')}`;

        // 2. Build Query Grouping Structures
        const isDetailed = showWorkType || showNatureOfWork || showTown;
        let sqlQuery = "";

        if (isDetailed) {
            let selectColumns = ["ct.type_name as name"];
            let groupByColumns = ["ct.type_name"];
            let joinClauses = ["JOIN complaint_types ct ON wr.complaint_type_id = ct.id"];

            if (showTown) {
                selectColumns.push("COALESCE(t.town, 'Unspecified') as town_name");
                groupByColumns.push("t.town");
                joinClauses.push("LEFT JOIN town t ON wr.town_id = t.id");
            }

            if (showWorkType || showNatureOfWork) {
                const subItemColumn = showWorkType ? 'cs.subtype_name' : 'wr.nature_of_work';
                if (showWorkType) {
                    joinClauses.push("LEFT JOIN complaint_subtypes cs ON wr.complaint_subtype_id = cs.id");
                }
                selectColumns.push(`COALESCE(${subItemColumn}, 'Unspecified') as sub_item`);
                groupByColumns.push(subItemColumn);
            }

            joinClauses.push("LEFT JOIN status s ON wr.status_id = s.id");

            sqlQuery = `
                SELECT 
                    ${selectColumns.join(', ')},
                    COUNT(wr.id) as total,
                    COUNT(CASE WHEN s.name = 'Completed' THEN 1 END) as completed,
                    COUNT(CASE WHEN s.name = 'In Progress' THEN 1 END) as active,
                    COUNT(CASE WHEN s.name = 'Pending' THEN 1 END) as pending,
                    
                    -- Department Summary Partition
                    SUM(COUNT(wr.id)) OVER(PARTITION BY ct.type_name) as dept_total_count,
                    SUM(COUNT(CASE WHEN s.name = 'Completed' THEN 1 END)) OVER(PARTITION BY ct.type_name) as dept_completed,
                    SUM(COUNT(CASE WHEN s.name = 'In Progress' THEN 1 END)) OVER(PARTITION BY ct.type_name) as dept_active,
                    SUM(COUNT(CASE WHEN s.name = 'Pending' THEN 1 END)) OVER(PARTITION BY ct.type_name) as dept_pending
                    
                    -- Town Summary Partition
                    ${showTown ? `,
                    SUM(COUNT(wr.id)) OVER(PARTITION BY ct.type_name, t.town) as town_total_count,
                    SUM(COUNT(CASE WHEN s.name = 'Completed' THEN 1 END)) OVER(PARTITION BY ct.type_name, t.town) as town_completed,
                    SUM(COUNT(CASE WHEN s.name = 'In Progress' THEN 1 END)) OVER(PARTITION BY ct.type_name, t.town) as town_active,
                    SUM(COUNT(CASE WHEN s.name = 'Pending' THEN 1 END)) OVER(PARTITION BY ct.type_name, t.town) as town_pending
                    ` : ''}
                FROM work_requests wr
                ${joinClauses.join('\n')}
                ${whereString}
                GROUP BY ${groupByColumns.join(', ')}
                ORDER BY ct.type_name ${showTown ? ', t.town' : ''} ${(showWorkType || showNatureOfWork) ? ', sub_item' : ''}`;
        } else {
            sqlQuery = `
                SELECT 
                    ct.type_name as name, 
                    COUNT(wr.id) as total,
                    COUNT(CASE WHEN s.name = 'Completed' THEN 1 END) as completed,
                    COUNT(CASE WHEN s.name = 'In Progress' THEN 1 END) as active,
                    COUNT(CASE WHEN s.name = 'Pending' THEN 1 END) as pending
                FROM work_requests wr
                JOIN complaint_types ct ON wr.complaint_type_id = ct.id
                LEFT JOIN status s ON wr.status_id = s.id
                ${whereString}
                GROUP BY ct.type_name
                ORDER BY ct.type_name`;
        }

        const dbResult = await query(sqlQuery);
        const reportData = dbResult.rows;

        // 3. Initialize PDF Engine
        const doc = new PDFDocument({ 
            margin: 50, 
            size: 'A4',
            bufferPages: true
        });

        doc._fontFamilies = {};
        doc._fontCount = 0;

        const chunks = [];
        doc.on('data', chunk => chunks.push(chunk));
        
        // Font Assignment
        if (fontBuffer) {
            doc.registerFont('Arial', fontBuffer);
            doc.font('Arial');
        } else {
            doc.font('Helvetica');
        }

        // --- FIXED Logo Execution: Format directly as Data URI String ---
        try {
            if (LOGO_BASE64 && LOGO_BASE64.length > 50) {
                // Ensure string format is explicitly defined for PDFKit's virtual stream compiler
                const cleanBase64 = LOGO_BASE64.replace(/^data:image\/png;base64,/, "");
                const dataUri = `data:image/png;base64,${cleanBase64}`;
                doc.image(dataUri, 50, 45, { height: 50 });
            }
        } catch (imgError) {
            console.error("Logo attachment bypassed:", imgError.message);
        }

        doc.fillColor('black').fontSize(14).text('KARACHI WATER & SEWERAGE CORPORATION', 100, 55);
        doc.fontSize(10).text('Works Management Portal', 100, 73);

        const timestamp = new Date().toLocaleString();
        doc.fillColor('#666666').fontSize(8);
        doc.text(`Generated On: ${timestamp}`, 350, 20, { align: 'right', width: 200, oblique: true });
        doc.text('Generated via WMP Portal', 350, 32, { align: 'right', width: 200, oblique: true });

        doc.moveTo(50, 100).lineTo(545, 100).strokeColor('#cccccc').lineWidth(1).stroke();

        doc.moveDown(3);
        doc.fillColor('black').fontSize(12).text('DEPARTMENT-WISE PERFORMANCE REPORT', 50, 118, { align: 'center', bold: true });

        if (dateFrom && dateTo) {
            doc.fontSize(10).text(`Period: ${dateFrom} to ${dateTo}`, { align: 'center' });
        }
        doc.moveDown(0.75);

        // --- CALCULATE DYNAMIC LAYOUT COLS & HEADERS ---
        let colWidths = [295, 50, 50, 50, 50]; 
        let headers = ['Department Name', 'Total', 'Completed', 'Active', 'Pending'];
        let hasThreeTextCols = false;

        if (isDetailed) {
            if (showTown && (showWorkType || showNatureOfWork)) {
                hasThreeTextCols = true;
                colWidths = [100, 100, 105, 50, 50, 50, 40]; 
                headers = ['Department', 'Town', showWorkType ? 'Work Type' : 'Nature of Work', 'Total', 'Completed', 'Active', 'Pending'];
            } else if (showTown) {
                colWidths = [150, 150, 50, 50, 50, 45];
                headers = ['Department Name', 'Town', 'Total', 'Completed', 'Active', 'Pending'];
            } else {
                colWidths = [150, 150, 50, 50, 50, 45];
                headers = ['Department Name', showWorkType ? 'Work Type' : 'Nature of Work', 'Total', 'Completed', 'Active', 'Pending'];
            }
        }

        const drawRow = (y, items, type = 'normal') => {
            let x = 50;
            let maxHeight = 0;
            items.forEach((text, i) => {
                const options = { width: colWidths[i], align: i < (hasThreeTextCols ? 3 : (isDetailed ? 2 : 1)) ? 'left' : 'center' };
                const textHeight = doc.heightOfString(text?.toString() || '', options);
                if (textHeight > maxHeight) maxHeight = textHeight;
            });

            const rowHeight = maxHeight + 10;
            const fullGridWidth = 495;

            if (type === 'header') {
                doc.fillColor('#1e3a8a').rect(50, y - 5, fullGridWidth, rowHeight).fill();
                doc.fillColor('white').fontSize(10);
            } else if (type === 'highlight') {
                doc.fillColor('#e2e8f0').rect(50, y - 5, fullGridWidth, rowHeight).fill();
                doc.fillColor('#1e3a8a').fontSize(10);
            } else if (type === 'town_highlight') {
                doc.fillColor('#d1fae5').rect(50, y - 5, fullGridWidth, rowHeight).fill();
                doc.fillColor('#065f46').fontSize(9);
            } else if (type === 'grand_total') {
                doc.fillColor('black').rect(50, y - 5, fullGridWidth, rowHeight).fill();
                doc.fillColor('white').fontSize(10);
            } else {
                doc.fillColor('black').fontSize(9);
            }

            x = 50;
            items.forEach((text, i) => {
                const isTextLeft = i < (hasThreeTextCols ? 3 : (isDetailed ? 2 : 1));
                doc.text(text?.toString() || '', x, y, { 
                    width: colWidths[i], 
                    align: isTextLeft ? 'left' : 'center' 
                });
                x += colWidths[i];
            });
            return rowHeight;
        };

        let currentY = doc.y + 15;
        const hHeight = drawRow(currentY, headers, 'header');
        currentY += hHeight + 10;

        let grandTotal = { t: 0, c: 0, a: 0, p: 0 };
        let lastDept = "";
        let lastTown = "";

        reportData.forEach((row) => {
            if (currentY > 730) { doc.addPage(); currentY = 50; }

            if (isDetailed) {
                if (row.name !== lastDept) {
                    const deptRowItems = hasThreeTextCols 
                        ? [row.name.toUpperCase(), "", "", row.dept_total_count, row.dept_completed, row.dept_active, row.dept_pending]
                        : [row.name.toUpperCase(), "", row.dept_total_count, row.dept_completed, row.dept_active, row.dept_pending];

                    const rowH = drawRow(currentY, deptRowItems, 'highlight');
                    currentY += rowH + 5;
                    lastDept = row.name;
                    lastTown = ""; 

                    grandTotal.t += parseInt(row.dept_total_count || 0);
                    grandTotal.c += parseInt(row.dept_completed || 0);
                    grandTotal.a += parseInt(row.dept_active || 0);
                    grandTotal.p += parseInt(row.dept_pending || 0);
                }

                if (currentY > 730) { doc.addPage(); currentY = 50; }

                if (hasThreeTextCols) {
                    if (row.town_name !== lastTown) {
                        const rowT = drawRow(currentY, [
                            "", 
                            row.town_name, 
                            "", 
                            row.town_total_count, 
                            row.town_completed, 
                            row.town_active, 
                            row.town_pending
                        ], 'town_highlight');
                        currentY += rowT + 4;
                        lastTown = row.town_name;
                    }

                    if (currentY > 730) { doc.addPage(); currentY = 50; }

                    const rowR = drawRow(currentY, [
                        "", 
                        "", 
                        row.sub_item, 
                        row.total, 
                        row.completed, 
                        row.active, 
                        row.pending
                    ], 'normal');
                    currentY += rowR + 2;

                } else if (showTown) {
                    const rowR = drawRow(currentY, [
                        "", 
                        row.town_name, 
                        row.total, 
                        row.completed, 
                        row.active, 
                        row.pending
                    ], 'normal');
                    currentY += rowR + 2;

                } else {
                    const rowR = drawRow(currentY, [
                        "", 
                        row.sub_item, 
                        row.total, 
                        row.completed, 
                        row.active, 
                        row.pending
                    ], 'normal');
                    currentY += rowR + 2;
                }
            } else {
                const rowR = drawRow(currentY, [row.name, row.total, row.completed, row.active, row.pending]);
                currentY += rowR + 5;
                grandTotal.t += parseInt(row.total || 0);
                grandTotal.c += parseInt(row.completed || 0);
                grandTotal.a += parseInt(row.active || 0);
                grandTotal.p += parseInt(row.pending || 0);
            }
        });

        if (currentY > 730) { doc.addPage(); currentY = 50; }

        const totalPaddingCols = colWidths.length - 5; 
        const grandTotalRowItems = ["GRAND TOTAL"];
        for (let i = 0; i < totalPaddingCols; i++) {
            grandTotalRowItems.push("");
        }
        grandTotalRowItems.push(grandTotal.t, grandTotal.c, grandTotal.a, grandTotal.p);

        drawRow(currentY + 10, grandTotalRowItems, 'grand_total');

        doc.end();
        const pdfBuffer = await new Promise(resolve => doc.on('end', () => resolve(Buffer.concat(chunks))));

        return new NextResponse(pdfBuffer, {
            headers: {
                'Content-Type': 'application/pdf',
                'Content-Disposition': 'attachment; filename="Department_Performance_Report.pdf"'
            }
        });

    } catch (error) {
        console.error("PDF Error:", error);
        return NextResponse.json({ success: false, message: error.message }, { status: 500 });
    }
}